  wd:Q8205 wdt:P154 ?episode.
  ?episode wdt:P31 wd:Q4099239;  # TV episode
         wdt:P577 ?date;
         wdt:P1479 ?performer.
  ?performer rdfs:label ?performerLabel.
  FILTER (LANG(?performerLabel) = "en").
} ORDER BY DESC(?date) LIMIT 1

